from flask import Flask, request
from flask_oauthlib.contrib.flask_oauth2 import OAuth2ResourceServer, OAuth2Error
from sqlalchemy import create_engine, Column, String
from sqlalchemy.orm import sessionmaker
from sqlalchemy.ext.declarative import declarative_base

# Database setup
Base = declarative_base()
engine = create_engine('sqlite:///tokens.db')
Session = sessionmaker(bind=engine)

class Token(Base):
    __tablename__ = 'tokens'
    id = Column(String, primary_key=True)

Base.metadata.create_all(engine)

# Flask app
app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret'

# OAuth 2.0 resource server
oauth = OAuth2ResourceServer(app)

@app.route('/api/protected')
@oauth.require_oauth()
def protected_endpoint():
    return 'This is a protected endpoint.'

# Token validation function
def validate_token(token):
    session = Session()
    token_exists = session.query(Token).filter_by(id=token).first() is not None
    session.close()
    return token_exists

# Configure OAuth 2.0 resource server
app.config['OAUTH2_JWT_VALIDATOR'] = validate_token

if __name__ == '__main__':
    app.run(debug=True)